import React, { useState } from 'react';
import Clients from './Clients';
import Tours from '.../../../Tours';
import Bookings from './Bookings';
import Countries from './Countries';

const Admin = () => {
  const [activeTab, setActiveTab] = useState('clients'); // Default to 'clients'

  const renderTabContent = () => {
    switch (activeTab) {
      case 'clients':
        return <Clients />;
      case 'tours':
        return <Tours />;
      case 'bookings':
        return <Bookings />;
      case 'countries':
        return <Countries />;
      default:
        return <Clients />;
    }
  };

  return (
    <div className="admin-container">
      <div className="tabs">
        <button onClick={() => setActiveTab('clients')}>Clients</button>
        <button onClick={() => setActiveTab('tours')}>Tours</button>
        <button onClick={() => setActiveTab('bookings')}>Bookings</button>
        <button onClick={() => setActiveTab('countries')}>Countries</button>
      </div>

      <div className="tab-content">
        {renderTabContent()}
      </div>
    </div>
  );
};

export default Admin;
